generated_oml:
// -----------------------------------------------------
// Acting Components
// -----------------------------------------------------
instance CartDriveStepperMotorController : DTDFVocab:ActingComponent [
    base:desc "Cart drive stepper motor with TMC4671‑Eval controller"
]

instance HoistStepperMotorController : DTDFVocab:ActingComponent [
    base:desc "Hoist stepper motor with TMC4671‑Eval controller"
]

instance EndEffectorElectromagnet : DTDFVocab:ActingComponent [
    base:desc "Electromagnet at the end of the hoist used to pick up and release pucks"
]

// -----------------------------------------------------
// Physical Sensing Components
// -----------------------------------------------------
instance SwingAngleEncoder : DTDFVocab:SensingComponent [
    base:desc "Swing‑angle encoder measuring hoist sway"
    DTDFVocab:producedData SwingAngleDataTransmitted
]

instance WindSpeedAnemometer : DTDFVocab:SensingComponent [
    base:desc "Anemometer measuring wind speed"
    DTDFVocab:producedData WindSpeedDataTransmitted
]

instance CartMotorFeedbackSensor : DTDFVocab:SensingComponent [
    base:desc "Controller feedback from the cart stepper motor driver"
    DTDFVocab:producedData CartMotorFeedbackDataTransmitted
]

instance HoistMotorFeedbackSensor : DTDFVocab:SensingComponent [
    base:desc "Controller feedback from the hoist stepper motor driver"
    DTDFVocab:producedData HoistMotorFeedbackDataTransmitted
]

// -----------------------------------------------------
// Data Transmitted (MQTT payloads)
// -----------------------------------------------------
instance SwingAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SwingAngleEncoder
]

instance WindSpeedDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom WindSpeedAnemometer
]

instance CartMotorFeedbackDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom CartMotorFeedbackSensor
]

instance HoistMotorFeedbackDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom HoistMotorFeedbackSensor
]

// -----------------------------------------------------
// Persistent Data (TimescaleDB)
// -----------------------------------------------------
instance SwingAngleTimeSeriesData : DTDFVocab:Data [
    base:desc "Historic time‑series of swing angle measurements stored in TimescaleDB"
    DTDFVocab:fromData SwingAngleDataTransmitted
    DTDFVocab:inputTo TimescaleDBEnabler
]

instance WindSpeedTimeSeriesData : DTDFVocab:Data [
    base:desc "Historic time‑series of wind speed measurements stored in TimescaleDB"
    DTDFVocab:fromData WindSpeedDataTransmitted
    DTDFVocab:inputTo TimescaleDBEnabler
]

instance CartMotorFeedbackTimeSeriesData : DTDFVocab:Data [
    base:desc "Historic time‑series of cart motor feedback stored in TimescaleDB"
    DTDFVocab:fromData CartMotorFeedbackDataTransmitted
    DTDFVocab:inputTo TimescaleDBEnabler
]

instance HoistMotorFeedbackTimeSeriesData : DTDFVocab:Data [
    base:desc "Historic time‑series of hoist motor feedback stored in TimescaleDB"
    DTDFVocab:fromData HoistMotorFeedbackDataTransmitted
    DTDFVocab:inputTo TimescaleDBEnabler
]

// -----------------------------------------------------
// Enablers (tools, platforms)
// -----------------------------------------------------
instance TimescaleDBEnabler : DTDFVocab:Enabler [
    base:desc "TimescaleDB PostgreSQL extension used for continuous state logging of sensor data"
    DTDFVocab:enables DataLoggingService
]

instance MQTTBrokerEnabler : DTDFVocab:Enabler [
    base:desc "Eclipse Mosquitto MQTT broker enabling asynchronous communication between containers"
    DTDFVocab:enables DataLoggingService, SimulationService, TrajectoryGeneratorService, ContinuousValidationService, HumanMachineInterfaceService
]

instance GrafanaEnabler : DTDFVocab:Enabler [
    base:desc "Grafana dashboard for visualising logged data and insights"
    DTDFVocab:enables DataVisualizationService
]

instance GantrylibEnabler : DTDFVocab:Enabler [
    base:desc "Gantrylib Python module (installed via pip) providing kinematic and dynamic simulation capabilities"
    DTDFVocab:enables TrajectoryGeneratorService, SimulationService, ContinuousValidationService
]

// -----------------------------------------------------
// Services
// -----------------------------------------------------
instance DataLoggingService : DTDFVocab:Service [
    base:desc "Service that subscribes to MQTT sensor topics and stores continuous state records in TimescaleDB"
    DTDFVocab:provides LoggingCompleteInsight
]

instance DataVisualizationService : DTDFVocab:Service [
    base:desc "Service offering Grafana dashboards for operators to monitor crane state"
    DTDFVocab:provides DashboardInsight
]

instance TrajectoryGeneratorService : DTDFVocab:Service [
    base:desc "Optimal trajectory generation service using the kinematic model to produce swing‑free paths"
    DTDFVocab:provides OptimalTrajectoryInsight
]

instance SimulationService : DTDFVocab:Service [
    base:desc "Simulation service providing a digital replica of the crane and its controllers"
    DTDFVocab:provides SimulatedTrajectoryInsight
]

instance ContinuousValidationService : DTDFVocab:Service [
    base:desc "Continuous validation service comparing measured and simulated trajectories and issuing alerts when deviations exceed thresholds"
    DTDFVocab:provides ValidationAlertInsight
]

instance HumanMachineInterfaceService : DTDFVocab:Service [
    base:desc "Human‑Machine Interface allowing operators to adjust parameters or intervene based on insights"
    DTDFVocab:provides OperatorControlAction
]

// -----------------------------------------------------
// Insights and Actions
// -----------------------------------------------------
instance LoggingCompleteInsight : DTDFVocab:Insight [
    base:desc "Indicates that sensor data has been successfully logged into TimescaleDB"
]

instance DashboardInsight : DTDFVocab:Insight [
    base:desc "Real‑time visualisation of crane state and performance metrics on Grafana"
]

instance OptimalTrajectoryInsight : DTDFVocab:Insight [
    base:desc "Optimal swing‑free trajectory computed by the Trajectory Generator"
]

instance SimulatedTrajectoryInsight : DTDFVocab:Insight [
    base:desc "Simulated crane trajectory for comparison with measured data"
]

instance ValidationAlertInsight : DTDFVocab:Insight [
    base:desc "Alert generated when measured trajectory deviates beyond the acceptable threshold"
]

instance OperatorControlAction : DTDFVocab:Action [
    base:desc "Operator can adjust control parameters or command the electromagnet via the HMI"
    DTDFVocab:IsAutomatic false
]

// -----------------------------------------------------
// Models / Data Artifacts
// -----------------------------------------------------
instance CraneCADModel : DTDFVocab:Model [
    base:desc "CAD geometry of the crane exported from Fusion‑360"
    DTDFVocab:inputTo GantrylibEnabler
]

instance CraneKinematicModel : DTDFVocab:Model [
    base:desc "Kinematic model used by the Trajectory Generator"
    DTDFVocab:inputTo GantrylibEnabler
]

instance CraneDynamicSimulationModel : DTDFVocab:Model [
    base:desc "Dynamic simulation model of the crane and its controllers"
    DTDFVocab:inputTo GantrylibEnabler
]

instance ValidationMetricsModel : DTDFVocab:Model [
    base:desc "Validation metrics representing distance between measured and simulated trajectories"
    DTDFVocab:inputTo GantrylibEnabler
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "Control Application receives trajectory commands from the Trajectory Generator Service (and operator inputs from the Human‑Machine Interface) and forwards motion set‑points to the Physical Crane Interface, which drives the cart and hoist motor controllers and activates the electromagnet via the Arduino."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A C4‑model architecture where the physical crane is interfaced by a Python program, connected to a Control Application, Logging Application and Human‑Machine Interface; the digital side consists of a TimescaleDB, MQTT broker, Grafana dashboard and three core services (Trajectory Generator, Simulation, Continuous Validation) that exchange messages over MQTT and share the database."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The twin covers the design stage (CAD models in Autodesk Fusion‑360), the manufacturing stage (physical crane hardware), and the operation stage (real‑time sensor data, logged trajectories, and validation during run‑time)."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Continuous Validation Service continuously compares executed trajectories with simulated ones, computes distance metrics, checks them against a predefined threshold, and raises alerts on the dashboard; the Simulation Service provides confidence bounds for trajectories, enabling quantitative fidelity assessment."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Inter‑service communication uses MQTT (Eclipse Mosquitto) for signaling; sensor and command data are exchanged over MQTT topics; time‑series data are written to and read from TimescaleDB via standard PostgreSQL SQL; Grafana accesses the database over HTTP/SQL."
]

instance dt_hosting_deployment : DTDFVocab:Deployment [
    base:desc "All components run on a single personal computer; the database, MQTT broker and Grafana are Docker‑containerized; the remaining Python containers are installed via pip; orchestration is performed with a docker‑compose file that starts the full stack with a single command."
]
